@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="10" @bind="content" @bind:event="oninput"></textarea>

<div class="d-flex align-items-center gap-2 mb-3">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

<script type="module" src="@Assets["Components/Pages/Notepad.razor.js"]"></script>

@code {
    private const string StorageKey = "notepad-content";
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private DateTime? lastSavedAt;
    private Timer? autoSaveTimer;
    private IJSObjectReference? module;
    private DotNetObjectReference<Notepad>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        dotNetRef = DotNetObjectReference.Create(this);
        module = await JS.InvokeAsync<IJSObjectReference>("import",
            $"./{Assets["Components/Pages/Notepad.razor.js"]}");

        var stored = await module.InvokeAsync<string?>("load", StorageKey);
        if (stored is not null)
        {
            content = stored;
            savedContent = stored;
            StateHasChanged();
        }

        await module.InvokeVoidAsync("registerBeforeUnload", dotNetRef);

        autoSaveTimer = new Timer(async _ =>
        {
            await InvokeAsync(async () =>
            {
                if (content != savedContent)
                {
                    await SaveAsync();
                    StateHasChanged();
                }
            });
        }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public bool HasUnsavedChanges() => content != savedContent;

    private async Task SaveAsync()
    {
        if (module is null) return;
        await module.InvokeVoidAsync("save", StorageKey, content);
        savedContent = content;
        lastSavedAt = DateTime.Now;
    }

    private async Task SaveNowAsync()
    {
        await SaveAsync();
    }

    private async Task ClearAsync()
    {
        content = string.Empty;
        savedContent = string.Empty;
        lastSavedAt = null;
        if (module is not null)
        {
            await module.InvokeVoidAsync("clear", StorageKey);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }
        if (module is not null)
        {
            await module.InvokeVoidAsync("unregisterBeforeUnload");
            await module.DisposeAsync();
        }
        dotNetRef?.Dispose();
    }
}

let dotNetRef = null;

function beforeUnloadHandler(e) {
    if (dotNetRef) {
        const hasChanges = dotNetRef.invokeMethod('HasUnsavedChanges');
        if (hasChanges) {
            e.preventDefault();
        }
    }
}

export function load(key) {
    return localStorage.getItem(key);
}

export function save(key, value) {
    localStorage.setItem(key, value);
}

export function clear(key) {
    localStorage.removeItem(key);
}

export function registerBeforeUnload(ref) {
    dotNetRef = ref;
    window.addEventListener('beforeunload', beforeUnloadHandler);
}

export function unregisterBeforeUnload() {
    window.removeEventListener('beforeunload', beforeUnloadHandler);
    dotNetRef = null;
}

